87	/* ---- %DEFINE / %IF / %ELSE / %ENDIF conditional compilation ---- */
88	
89	#define DEF_MAX  32   /* max compile-time defines */
90	#define COND_MAX  8   /* max %IF nesting depth */
91	
92	/* Define table: name -> value (value may be empty string) */
93	char *def_names[DEF_MAX];
94	char *def_values[DEF_MAX];
95	int   def_count;
96	
97	/* Conditional compilation stack */
98	int cond_active[COND_MAX];   /* 1 = emitting tokens, 0 = skipping */
99	int cond_seen_true[COND_MAX]; /* 1 = some branch was true (for else) */
100	int cond_depth;              /* current nesting depth */
101	
102	void def_init(void) {
103	    def_count = 0;
104	    cond_depth = 0;
105	}
106	
107	/* Add or update a define */
108	void def_set(char *name, char *value) {
109	    int i = 0;
110	    while (i < def_count) {
111	        if (str_eq_nocase(name, def_names[i])) {
112	            def_values[i] = value;
113	            return;
114	        }
115	        i = i + 1;
