    int i = 0;
    int val = 0;
    while (lex_pos < lex_len && is_digit(lex_peek()) && i < TOK_TEXT_MAX - 1) {
        int d = lex_advance();
        cur_text[i] = d;
        val = val * 10 + (d - 48);
        i = i + 1;
    }
    cur_text[i] = 0;
    cur_type = TOK_NUM;
    cur_ival = val;
    return TOK_NUM;
