    test_parse_program("single DCL",
        "DCL COUNT INT(24);");

    /* Test 2: multiple global DCLs */
    test_parse_program("multi DCL",
        "DCL X INT(24); DCL Y INT(24); DCL Z BYTE;");

    /* Test 3: single PROC */
