                print_int(sym_offset[idx]);
                uart_putchar(10);

                sym_exit_scope();
                break;
            }
            child = nd_next[child];
        }

        layout_print_frame();
    } else {
        uart_puts("  PARSE ERROR");
    }

    /* Test 12: multiple static allocations track correctly */
    uart_puts("--- static tracking ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();

    parse_init("DCL A INT(24); DCL B(10) BYTE; DCL C WORD;");
