        }
        if (!str_find(out, "sw      r1,0(r0)")) {
            uart_puts("  FAIL: missing sw r1,0(r0)");
            errs = errs + 1;
        }
    }

    /* Test 2: NAKED procedure with ASM body (interrupt handler stub) */
    uart_puts("--- asm: NAKED interrupt handler ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();
    emit_init();
    cg_init();
    cg_static_init();

