    idx = sym_insert("BUFPTR", TYPE_PTR, 3, STOR_AUTO);
    uart_putstr("insert BUFPTR: idx=");
    print_int(idx);
    uart_putchar(10);

    uart_putstr("global scope size: ");
    print_int(sym_scope_size());
    uart_putchar(10);

    /* Test 2: lookup in global scope */
    uart_puts("--- lookup global ---");
