    src = "%DEFINE OUTER_FLAG;"
          "%IF DEFINED(OUTER_FLAG);"
            "%DEFINE INNER_FLAG;"
            "%IF DEFINED(INNER_FLAG);"
              "DCL DEEP INT(24);"
            "%ENDIF;"
          "%ENDIF;";
    lex_init(src, str_len(src));
