    arena_init();
    src = "%IF DEFINED(NOPE);"
            "%IF DEFINED(ALSO_NOPE);"
              "DCL HIDDEN INT(24);"
            "%ENDIF;"
          "%ENDIF;"
          "DCL FOUND BYTE;";
    lex_init(src, str_len(src));
    lex_scan(); /* DCL */
