        uart_putstr(" offset=");
        print_int(td_field_offset(desc, fidx));
        uart_putstr(" type=");
        uart_puts(nd_type_name(td_field_type(desc, fidx)));

        fidx = td_field_lookup(desc, "Z");
        uart_putstr("  lookup Z (missing): idx=");
