        print_int(sym_offset[idx]);
        uart_putchar(10);

        idx = sym_lookup("TEMP");
        uart_putstr("  TEMP(auto): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        idx = sym_lookup("BUF");
        uart_putstr("  BUF(auto): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        sym_exit_scope();
    } else {
