        "   GEN DO;"
        "      'mvi r0,{CODE}';"
        "   END;"
        "   GEN DO;"
        "      'la r1,{TARGET}';"
        "      'svc 0';"
        "   END;"
        "END;";

    lex_init(src, str_len(src));
