            uart_puts("  OK: has PRINT_INT proc");
        }

        /* Verify MAIN procedure */
        if (!str_find(out, "_MAIN:")) {
            uart_puts("  FAIL: missing MAIN proc");
            errs = errs + 1;
        } else {
            uart_puts("  OK: has MAIN proc");
        }

        /* Verify DO count loop (call to PRINT_INT inside loop) */
