    else if (n == 21) { uart_puts("=== DO WHILE Codegen Tests ==="); test_do_while_codegen(); }
    else if (n == 22) { uart_puts("=== DO COUNT Codegen Tests ==="); test_do_count_codegen(); }
    else if (n == 23) { uart_puts("=== Record Codegen Tests ==="); test_record_codegen(); }
