1	/* descr_macros.msw -- Inline asm macros for descriptors */
2	
3	/* DESC_COPY: copy 6 bytes. Clobbers r0,r1,r2 */
4	MACRODEF DESC_COPY;
5	    REQUIRED DST(expr); REQUIRED SRC(expr);
6	    GEN DO;
7	        'la r1,{SRC}'; 'la r2,{DST}';
8	        'lb r0,0(r1)'; 'sb r0,0(r2)';
9	        'lb r0,1(r1)'; 'sb r0,1(r2)';
10	        'lb r0,2(r1)'; 'sb r0,2(r2)';
11	        'lw r0,3(r1)'; 'sw r0,3(r2)';
12	    END;
13	END;
14	
15	/* BUILD_NULL: zero a descriptor. Clobbers r0,r2 */
16	MACRODEF BUILD_NULL;
17	    REQUIRED PTR(expr);
18	    GEN DO;
19	        'la r2,{PTR}'; 'lc r0,0';
20	        'sb r0,0(r2)'; 'sb r0,1(r2)';
21	        'sb r0,2(r2)'; 'sw r0,3(r2)';
22	    END;
23	END;
