    parse_init("%INCLUDE DEFS; PROC MAIN(); COUNT = 42; END;");
    prog = parse_program();
    if (parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(parse_errmsg);
        errs = errs + 1;
    } else {
        layout_globals(prog);
        cg_program_procs(prog);
        out = emit_output();
        uart_putstr(out);

        if (!str_find(out, "_MAIN:")) {
            uart_puts("  FAIL: missing proc label _MAIN");
            errs = errs + 1;
