void test_counted_loop(void) {
    int errs;
    char *src;
    char *out;

    errs = 0;

    /* Counted loop PL/SW source -- DO I = 1 TO 10, PRINT_INT */
    src = "DCL DIGITS(12) CHAR;"
          "PRINT_INT: PROC(N INT);"
          "  DCL D INT;"
