    errs = 0;

    /* Record and pointer PL/SW source */
    src = "DCL DIGITS(12) CHAR;"
          "PRINT_INT: PROC(N INT);"
          "  DCL D INT;"
          "  DCL POS INT;"
          "  IF (N = 0) THEN DO;"
          "    CALL UART_PUTCHAR(48);"
