          "    DIGITS(POS) = N - D * 10 + 48;"
          "    N = D;"
          "    POS = POS + 1;"
          "  END;"
          "  DO WHILE (POS > 0);"
          "    POS = POS - 1;"
          "    CALL UART_PUTCHAR(DIGITS(POS));"
