          "    RETURN;"
          "  END;"
          "  POS = 0;"
          "  DO WHILE (N > 0);"
          "    D = N / 10;"
          "    DIGITS(POS) = N - D * 10 + 48;"
          "    N = D;"
          "    POS = POS + 1;"
