    } else {
        uart_puts("  OK: TAG_NULL -> TOK_NUM 0");
    }

    /* Test 11: %DEFINE value substitution (text/keyword) */
    uart_puts("Test 11: %DEFINE value substitution (text)");
    arena_init();
    src = "%DEFINE MYTYPE INT;"
          "DCL A MYTYPE(24);";
    lex_init(src, str_len(src));
