    uart_putstr("  array desc idx=");
    print_int(desc);
    uart_putchar(10);
    td_print(desc);

    desc = td_make_array(TYPE_INT24, 10);
    uart_putstr("  array desc idx=");
    print_int(desc);
    uart_putchar(10);
