          "    N = D;"
          "    POS = POS + 1;"
          "  END;"
          "  DO WHILE (POS > 0);"
          "    POS = POS - 1;"
          "    CALL UART_PUTCHAR(DIGITS(POS));"
          "  END;"
          "END;"
          "MAIN: PROC;"
          "  DCL I INT;"
          "  DO I = 1 TO 10;"
