        /* End label must exist */
        if (!str_find(out, "L0:")) {
            uart_puts("  FAIL: missing end label (L0)");
            errs = errs + 1;
        }
        /* No jmp to label (no else means no jump-over-else) */
        if (str_find(out, "bra     L")) {
            uart_puts("  FAIL: unexpected jmp in if/then (no else)");
            errs = errs + 1;
        }
    }

