        }
        if (!str_find(out, "L1:")) {
            uart_puts("  FAIL: missing end label (L1)");
            errs = errs + 1;
        }
    }

    /* Test 3: IF/THEN/ELSE with DO blocks */
    uart_puts("--- if: block if/then/else ---");
