    else if (n == 30) { uart_puts("=== Conditional Compilation Tests ==="); test_conditional(); }
    else if (n == 31) { uart_puts("=== Hello World Compile ==="); test_hello_world(); }
    else if (n == 32) { uart_puts("=== LED Toggle Compile ==="); test_led_toggle(); }
